import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getAlbum } from '../api/albumService';

export default function AlbumDetail(){
  const { id } = useParams();
  const [item, setItem] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(()=>{ setLoading(true); getAlbum(id).then(r=>setItem(r.data)).catch(()=>{}).finally(()=>setLoading(false)); },[id]);

  if(loading) return <div>Chargement...</div>;
  if(!item) return <div>Non trouvé</div>;

  return (
    <div>
      <h2>{item.titre || item.title}</h2>
      <p>ID: {item.id}</p>
      <p>Année: {item.annee || '—'}</p>
      <p>
        <Link to="/albums">Retour</Link>
      </p>
    </div>
  );
}
